@font-face {
  font-family: Inter;
  src: url(https://tinybase.org/fonts/inter.woff2) format("woff2");
}

* {
  box-sizing: border-box;
}

body {
  background: white;
  font-family: Inter, sans-serif;
  margin: 0;
}

main {
  margin: 2rem auto;
  max-width: 52rem;
  padding: 0 2rem;
}

.chart {
  background: #f6f8fb;
  border: 1px solid #d9e2ec;
  border-radius: 0.5rem;
  box-shadow: 0 0.75rem 2rem #26364a1a;
  color: #1f2937;
  display: block;
  font-size: 12px;
  height: 20rem;
  padding: 1rem;
  width: 100%;
}

@media (max-width: 40rem) {
  main {
    padding: 0 1rem;
  }
}

.chart {
  .grid {
    color: #d8e1eb;
    stroke-dasharray: 4 6;
  }

  .axes {
    color: #677489;

    .title {
      fill: #1f2937;
      font-weight: 700;
    }
  }
}

.chart {
  .plot {
    .area {
      fill: #0ea5e9;
      fill-opacity: 0.12;
    }

    .line {
      stroke: #0284c7;
      stroke-linecap: round;
      stroke-linejoin: round;
      stroke-opacity: 1;
      stroke-width: 3;
    }

    .points {
      fill: white;
      stroke: #0284c7;
      stroke-width: 2;
    }
  }
}

.chart {
  .tooltip-lines {
    stroke: #0284c7;
    stroke-dasharray: 3 3;
    stroke-opacity: 0.35;
  }

  .tooltip {
    font-weight: 700;

    rect {
      fill: #172033;
      fill-opacity: 0.94;
    }

    text {
      fill: white;
    }
  }
}

